using TestContext context = new();
context.Services.AddBlazoriseTests().AddBootstrap5Providers().AddEmptyIconProvider().AddMemoryCache();
context.JSInterop.AddBlazoriseDataGrid();

var data = new[]
{
    new Employee { Name = "Active", Department = "Female", City = "A" },
    new Employee { Name = "Inactive", Department = "Female", City = "B" },
    new Employee { Name = "Active", Department = "Male", City = "C" },
    new Employee { Name = "Inactive", Department = "Male", City = "D" },
