    {
        builder.Append( "b-datagrid" );

        if ( !string.IsNullOrWhiteSpace( Class ) )
        {
            builder.Append( Class );
        }

        if ( !string.IsNullOrWhiteSpace( Classes?.Self ) )
        {
            builder.Append( Classes.Self );
        }
