    private void BuildStyles( StyleBuilder builder )
    {
        if ( !string.IsNullOrWhiteSpace( Styles?.Self ) )
        {
            builder.Append( Styles.Self.Trim().TrimEnd( ';' ) );
        }

        if ( !string.IsNullOrWhiteSpace( Style ) )
        {
            builder.Append( Style.Trim().TrimEnd( ';' ) );
        }
    }

