    {
        if ( handler.HasDelegate )
        {
            var args = new CancellableRowChange<TItem, TValues>( item, newItem, editedCellValues );

            await handler.InvokeAsync( args );

            if ( args.Cancel )
            {
                return false;
            }
        }

        return true;
    }

