-    /// <summary>
-    /// Gets the current state of the DataGrid.
-    /// </summary>
-    /// <returns></returns>
-    public Task<DataGridState<TItem>> GetState()
-    {
-        var dataGridState = new DataGridState<TItem>()
-        {
-            Page = Page,
-            PageSize = PageSize,
-            EditState = EditState,
-            EditItem = editState == DataGridEditState.None ? default : editItem,
-            SelectedRow = SelectedRow,
-            SelectedRows = SelectedRows
-        };
-
-        if ( !SortByColumns.IsNullOrEmpty() )
-        {
-            dataGridState.ColumnSortStates = SortByColumns.Select( x => new DataGridColumnSortState<TItem>( x.Field, x.CurrentSortDirection ) ).ToList();
-        }
-
-        if ( Columns.Exists( x => x.Filter?.SearchValue != null ) )
-        {
-            dataGridState.ColumnFilterStates = Columns.Where( x => x.Filter?.SearchValue is not null ).Select( x => new DataGridColumnFilterState<TItem>( x.Field, x.Filter.SearchValue )
-            {
-                FilterMethod = x.GetFilterMethod() ?? x.GetDataGridFilterMethodAsColumn(),
-            } ).ToList();
-        }
-
-        dataGridState.ColumnDisplayingStates = Columns.Where( x => x.IsRegularColumn ).Select( x => new DataGridColumnDisplayingState<TItem>( x.Field, x.Displaying, x.GetDisplayOrder() ) ).ToList();
-
-        if ( GroupBy is null && !groupableColumns.IsNullOrEmpty() )
-        {
-            dataGridState.ColumnGroupingStates = groupableColumns.Select( x => new DataGridColumnGroupingState<TItem>( x.Field ) ).ToList();
-        }
-
-        return Task.FromResult( dataGridState );
-    }
