{
    Console.Error.WriteLine( ex.Message );
    return 1;
}

static void VerifySingleLevelGroupingHasNoNestedGroups()
{
    using TestContext context = CreateContext();
    var (dataGrid, component, departmentColumn, _) = RenderGrid( context );

    dataGrid.Instance.AddGroupColumn( departmentColumn.Instance );
    component.Render();

    var grouped = dataGrid.Instance.DisplayGroupedData.ToList();
    Console.WriteLine( "single-level: " + Describe( grouped ) );

    if ( grouped.Count != 2 || grouped.Any( x => x.NestedGroup is not null ) )
    {
        throw new InvalidOperationException( "Single-level grouping should create only top-level groups." );
    }
}

static void VerifyTwoLevelGroupingCreatesNestedGroups()
{
    using TestContext context = CreateContext();
    var (dataGrid, component, departmentColumn, nameColumn) = RenderGrid( context );

    dataGrid.Instance.AddGroupColumn( departmentColumn.Instance );
    dataGrid.Instance.AddGroupColumn( nameColumn.Instance );
    component.Render();

    var grouped = dataGrid.Instance.DisplayGroupedData.ToList();
    Console.WriteLine( "two-level: " + Describe( grouped ) );

    if ( grouped.Count != 2 || grouped.Any( x => x.NestedGroup is null ) || grouped.SelectMany( x => x.NestedGroup ).Count() != 4 )
    {
        throw new InvalidOperationException( "Expected two top-level groups, each with nested Active/Inactive groups." );
    }
}

static void VerifyRemovingSecondLevelClearsNestedGroups()
{
    using TestContext context = CreateContext();
    var (dataGrid, component, departmentColumn, nameColumn) = RenderGrid( context );

    dataGrid.Instance.AddGroupColumn( departmentColumn.Instance );
    dataGrid.Instance.AddGroupColumn( nameColumn.Instance );
    dataGrid.Instance.RemoveGroupColumn( nameColumn.Instance );
    component.Render();

    var grouped = dataGrid.Instance.DisplayGroupedData.ToList();
    Console.WriteLine( "after-removal: " + Describe( grouped ) );

    if ( grouped.Count != 2 || grouped.Any( x => x.NestedGroup is not null ) )
    {
        throw new InvalidOperationException( "Removing the second grouped column should clear nested groups." );
    }
}

static TestContext CreateContext()
{
    TestContext context = new();
    context.Services.AddBlazoriseTests().AddBootstrap5Providers().AddEmptyIconProvider().AddMemoryCache();
    context.JSInterop.AddBlazoriseDataGrid();
    return context;
}

