{
    var data = new[]
    {
        new Employee { Name = "Active", Department = "Female", City = "A" },
        new Employee { Name = "Inactive", Department = "Female", City = "B" },
        new Employee { Name = "Active", Department = "Male", City = "C" },
        new Employee { Name = "Inactive", Department = "Male", City = "D" },
    };

    var component = context.RenderComponent<BasicTestApp.Client.DataGridGroupingComponent>( parameters => parameters.Add( x => x.Data, data ) );
    var dataGrid = component.FindComponent<DataGrid<Employee>>();
    var columns = dataGrid.FindComponents<DataGridColumn<Employee>>();
    var departmentColumn = columns.Single( x => x.Instance.Field == nameof( Employee.Department ) );
    var nameColumn = columns.Single( x => x.Instance.Field == nameof( Employee.Name ) );

    return (dataGrid, component, departmentColumn, nameColumn);
}

static string Describe( IEnumerable<GroupContext<Employee>> grouped )
    => string.Join( "; ", grouped.Select( x => $"{x.Key}: nested={x.NestedGroup?.Count() ?? 0}, items={x.Items.Count()}" ) );
